SELECT garment_type_name 
FROM garment_types 
WHERE garment_type_id = 0;

SELECT p.product_name, g.garment_type_name
FROM products p
JOIN garment_types g ON p.garment_type_id = g.garment_type_id;

SELECT size_name
FROM sizes
WHERE garment_type_id = (SELECT garment_type_id FROM garment_types WHERE garment_type_name = 'Bottoms');
